from flask import Flask, request, jsonify
import pickle
import os
import tempfile
import json
import re
from werkzeug.utils import secure_filename
from functools import wraps

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads/'
app.config['ALLOWED_EXTENSIONS'] = {'pkl'}
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16 MB

# Ensure upload folder exists
os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

def secure_model_load(file_path):
    with open(file_path, 'rb') as f:
        model = pickle.load(f)
    return model

def authenticate(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Implement authentication logic here
        return f(*args, **kwargs)
    return decorated_function

@app.route('/upload_model', methods=['POST'])
@authenticate
def upload_model():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        return jsonify({'message': 'Model uploaded successfully', 'file_path': file_path}), 201
    return jsonify({'error': 'File type not allowed'}), 400

@app.route('/predict', methods=['POST'])
@authenticate
def predict():
    data = request.get_json()
    model_file_path = data.get('model_file_path')
    input_data = data.get('input_data')

    if not model_file_path or not os.path.exists(model_file_path):
        return jsonify({'error': 'Model file not found'}), 404

    try:
        model = secure_model_load(model_file_path)
        prediction = model.predict(input_data)  # Assuming model has a predict method
        return jsonify({'prediction': prediction.tolist()}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)